        ["algo" => 656, "uuid" => "4601ff", "name" => "noise-xx", "type" => "protocol", "status" => "active", "title" => "Noise XX", "description_md" => "Noise XX is the most general Noise pattern for mutual authentication where parties exchange static keys during the handshake with identity hiding. Both static keys are transmitted encrypted.\n\nNoise XX provides mutual authentication without any pre-provisioned keys. Used in libp2p (IPFS) and as a general-purpose secure channel protocol.", "mental_model" => "General mutual auth Noise -- XX, both keys encrypted in handshake, libp2p standard.", "purpose" => ["general mutual auth noise, no pre-provisioning"], "good_for" => ["libp2p ipfs", "general secure channels", "mutual auth no pre-provisioned keys"], "avoid_for" => ["pre-provisioned keys (noise-kk more efficient)", "anonymous channels"], "pros" => ["no pre-provisioned keys", "mutual auth", "identity hiding", "libp2p standard", "general purpose"], "cons" => ["3 round trips", "slightly heavier than kk"], "difficulty" => 2, "security" => 5, "quantum_impact" => "DH-based.", "post_quantum_status" => 1, "example" => ["scenario" => "libp2p Noise XX mutual auth", "input" => ["e_i" => "initiator ephemeral", "e_r" => "responder ephemeral"], "output" => ["session" => "mutually authenticated"]], "flow" => ["-> e", "<- e, ee, s, es", "-> s, se", "session keys"], "related" => ["noise-ik", "noise-kk", "noise-xk", "signal-x3dh"]],
        ["algo" => 657, "uuid" => "ee58d4", "name" => "noise-ikpsk2", "type" => "protocol", "status" => "active", "title" => "Noise IKpsk2", "description_md" => "Noise IKpsk2 is Noise IK with a Pre-Shared Key (PSK) modifier at message 2. This is the WireGuard VPN handshake pattern -- combines static DH mutual authentication with a PSK for additional security.\n\nWireGuard uses Noise IKpsk2 as its exact handshake protocol. The PSK provides an additional layer of defense.", "mental_model" => "WireGuard handshake -- Noise IK + PSK, the exact WireGuard VPN protocol.", "purpose" => ["wireguard vpn handshake (noise ik + psk)"], "good_for" => ["wireguard vpn", "psk-hardened mutual auth", "iot vpn"], "avoid_for" => ["no-psk environments (noise-ik)"], "pros" => ["wireguard standard", "psk additional security", "1 rtt mutual auth", "forward secret"], "cons" => ["psk management burden"], "difficulty" => 2, "security" => 5, "quantum_impact" => "DH quantum-vulnerable; PSK provides partial PQ protection.", "post_quantum_status" => 2, "example" => ["scenario" => "WireGuard VPN peer handshake", "input" => ["s_i" => "peer static key", "rs" => "responder static", "psk" => "pre-shared key"], "output" => ["session" => "wireguard session keys"]], "flow" => ["-> e, es, s, ss", "<- e, ee, se, psk", "WireGuard transport keys derived"], "related" => ["wireguard", "noise-ik", "noise-kk"]],
        ["algo" => 658, "uuid" => "a1174d", "name" => "signal-x3dh", "type" => "protocol", "status" => "active", "title" => "Signal X3DH", "description_md" => "X3DH (Extended Triple Diffie-Hellman) is the Signal Protocol key agreement used to establish initial shared secrets between parties who may be offline. Uses identity keys, signed prekeys, and one-time prekeys.\n\nX3DH allows Alice to send an initial encrypted message to Bob even if Bob is offline, using Bob's pre-published key bundle.", "mental_model" => "Async key agreement -- Signal X3DH, offline initial messages, identity+prekey bundles.", "purpose" => ["async initial key agreement (signal)"], "good_for" => ["signal initial messages", "offline async e2ee setup", "whatsapp initial e2ee"], "avoid_for" => ["online protocols (noise-xx simpler)", "non-signal ecosystems"], "pros" => ["works offline (async)", "forward secrecy", "deniability", "signal standard"], "cons" => ["prekey bundle required", "server must store prekeys"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DH-based; vulnerable to quantum.", "post_quantum_status" => 1, "example" => ["scenario" => "Signal initial message setup", "input" => ["IK_b" => "Bob identity key", "SPK_b" => "signed prekey", "OPK_b" => "one-time prekey"], "output" => ["sk" => "shared master secret"]], "flow" => ["Alice fetches Bob's prekey bundle", "4x DH: IK_a+IK_b, IK_a+SPK_b, EK_a+IK_b, EK_a+SPK_b", "KDF -> shared key SK"], "related" => ["signal-double-ratchet", "pqxdh", "noise-ik", "opaque"]],
        ["algo" => 659, "uuid" => "8172e0", "name" => "signal-double-ratchet", "type" => "protocol", "status" => "active", "title" => "Signal Double Ratchet", "description_md" => "The Signal Double Ratchet algorithm combines a Diffie-Hellman ratchet with a symmetric-key ratchet (KDF chain) for forward secrecy and break-in recovery. Used in Signal, WhatsApp, Facebook Messenger.\n\nThe Double Ratchet provides per-message forward secrecy (compromise of one message key doesn't compromise others) and healing (break-in recovery after compromise).", "mental_model" => "Per-message forward secrecy + break-in recovery -- Signal/WhatsApp ratchet, gold standard e2ee.", "purpose" => ["forward secret per-message encryption (signal)"], "good_for" => ["signal whatsapp messenger e2ee", "per-message fs and break-in recovery"], "avoid_for" => ["non-messaging (overhead)"], "pros" => ["per-message forward secrecy", "break-in recovery", "signal/whatsapp standard", "post-compromise security"], "cons" => ["message ordering handling complex", "state management"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DH ratchet quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Signal message ratchet forward secrecy", "input" => ["ratchet_state" => "dh+kdf state", "msg" => "plaintext"], "output" => ["ciphertext" => "double-ratchet encrypted"]], "flow" => ["DH ratchet: new DH key per ratchet step", "KDF chain: derive per-message keys from chain key", "send/receive ratchets interleaved"], "related" => ["signal-x3dh", "pqxdh", "mls", "sesame"]],
        ["algo" => 660, "uuid" => "b4e45b", "name" => "opaque", "type" => "protocol", "status" => "active", "title" => "OPAQUE", "description_md" => "OPAQUE is an asymmetric PAKE (Password Authenticated Key Exchange) that resists pre-computation attacks and server-side compromise. No password ever sent to server -- even the server doesn't learn it.\n\nOPAQUE is in IETF standardization. Prevents credential stuffing because even if server is compromised, passwords cannot be recovered without the client's secret.", "mental_model" => "Asymmetric PAKE -- OPAQUE, server never learns password, compromise-resistant login.", "purpose" => ["asymmetric pake: server-secret-free password auth"], "good_for" => ["compromise-resistant login", "ietf pake standard", "prevent server compromise password leak"], "avoid_for" => ["simple password check (srp simpler)", "multi-party (cpace/spake2)"], "pros" => ["server never has password", "ietf standard", "offline attack resistant", "credential stuffing resistant"], "cons" => ["complex (oblivious prf)", "server stores per-user opaque record"], "difficulty" => 4, "security" => 5, "quantum_impact" => "DH-based; classical for now.", "post_quantum_status" => 1, "example" => ["scenario" => "OPAQUE registration and login", "input" => ["password" => "user password", "oprf" => "oblivious prf evaluation"], "output" => ["session_key" => "authenticated shared key"]], "flow" => ["registration: client-only OPRF envelope stored at server", "login: OPRF blind eval + key exchange", "server learns nothing about password"], "related" => ["spake2", "spake2+", "cpace", "srp"]],
        ["algo" => 661, "uuid" => "6b6e13", "name" => "spake2", "type" => "protocol", "status" => "active", "title" => "SPAKE2", "description_md" => "SPAKE2 is a symmetric PAKE protocol that allows two parties sharing a password to establish a shared key. Based on two fixed random group elements multiplied by the password-derived scalar.\n\nSPAKE2 is simple, efficient, and has security proofs. Used in Kerberos (RFC 8120), FIDO2, and Chrome/Android attestation.", "mental_model" => "Simple symmetric PAKE -- SPAKE2, password to shared key, Kerberos/FIDO2 standard.", "purpose" => ["symmetric pake: password to shared key"], "good_for" => ["kerberos pake", "fido2 device pairing", "simple symmetric pake"], "avoid_for" => ["server compromise protection (opaque)", "augmented (spake2+)"], "pros" => ["simple", "efficient", "security proofs", "kerberos rfc standard", "fido2 pairing"], "cons" => ["symmetric (server has verifier)", "not augmented"], "difficulty" => 2, "security" => 4, "quantum_impact" => "DL-based.", "post_quantum_status" => 1, "example" => ["scenario" => "SPAKE2 device pairing", "input" => ["password" => "shared PIN", "M" => "group element"], "output" => ["session_key" => "spake2 shared key"]], "flow" => ["A: X = x*G + w*M, B: Y = y*G + w*N", "exchange X,Y", "KDF(X,Y,w) = session key"], "related" => ["spake2+", "cpace", "opaque", "dragonfly"]],
        ["algo" => 662, "uuid" => "f73057", "name" => "spake2+", "type" => "protocol", "status" => "active", "title" => "SPAKE2+", "description_md" => "SPAKE2+ is an augmented PAKE that separates client and server roles so a server compromise doesn't directly reveal the password. The server stores a password verifier, not the password.\n\nSPAKE2+ is used in Apple HomeKit and iCloud Keychain pairing. Augmented means the server stores W0, W1 derived from password but can't impersonate the client.", "mental_model" => "Augmented PAKE -- SPAKE2+, server verifier only, Apple HomeKit standard.", "purpose" => ["augmented pake (server verifier, not password)"], "good_for" => ["apple homekit pairing", "icloud keychain", "server-verifier pake"], "avoid_for" => ["full asymmetric pake (opaque)"], "pros" => ["augmented server-verifier", "apple homekit standard", "server compromise limited damage"], "cons" => ["server still has verifier (offline attack possible)"], "difficulty" => 2, "security" => 4, "quantum_impact" => "DL-based.", "post_quantum_status" => 1, "example" => ["scenario" => "Apple HomeKit accessory pairing", "input" => ["password" => "setup code", "W0_W1" => "server verifier pair"], "output" => ["session_key" => "homekit session"]], "flow" => ["SPAKE2+ augmented exchange", "server uses W0,W1 not raw password"], "related" => ["spake2", "opaque", "cpace", "dragonfly"]],
        ["algo" => 665, "uuid" => "6cd1cd", "name" => "dragonfly", "type" => "protocol", "status" => "active", "title" => "Dragonfly / SAE", "description_md" => "Dragonfly (SAE -- Simultaneous Authentication of Equals) is a PAKE used in WPA3 Wi-Fi authentication. Provides forward secrecy for Wi-Fi connections.\n\nSAE/Dragonfly replaced WPA2-PSK's vulnerability to offline dictionary attacks. Specified in IEEE 802.11-2016.", "mental_model" => "WPA3 PAKE -- Dragonfly/SAE, Wi-Fi forward secrecy, offline attack resistant.", "purpose" => ["wpa3 wifi password authentication"], "good_for" => ["wpa3 wifi authentication", "forward secret wifi", "offline attack resistant wifi"], "avoid_for" => ["non-wifi (use opaque/spake2)"], "pros" => ["wpa3 standard", "forward secrecy", "offline attack resistant", "ieee 802.11 standard"], "cons" => ["timing side-channels (historical)", "wifi-specific"], "difficulty" => 2, "security" => 4, "quantum_impact" => "DL-based.", "post_quantum_status" => 1, "example" => ["scenario" => "WPA3 Wi-Fi SAE handshake", "input" => ["password" => "wifi passphrase", "MAC_a" => "peer MACs"], "output" => ["PMK" => "pairwise master key"]], "flow" => ["commit: send scalar/element derived from pw", "confirm: verify commit", "PMK derived"], "related" => ["spake2", "cpace", "opaque"]],
        ["algo" => 667, "uuid" => "cb79ae", "name" => "otrv4", "type" => "protocol", "status" => "active", "title" => "OTRv4", "description_md" => "OTRv4 (Off-the-Record Messaging version 4) is an upgraded OTR protocol with post-quantum protection (using CRYSTALS-Kyber), better forward secrecy, and deniability. Used in Briar and Cwtch.\n\nOTRv4 adds a post-quantum initial key exchange on top of X25519 to protect against harvest-now-decrypt-later attacks.", "mental_model" => "PQ-upgraded OTR -- OTRv4, forward secrecy + deniability + Kyber initial key exchange.", "purpose" => ["post-quantum forward-secret deniable messaging"], "good_for" => ["forward secret deniable messaging", "briar cwtch e2ee", "pq-protected ot messaging"], "avoid_for" => ["signal (double ratchet better)", "simple e2ee (noise-xx)"], "pros" => ["deniability", "forward secrecy", "post-quantum initial ke (kyber)", "briar cwtch standard"], "cons" => ["complex", "niche deployment"], "difficulty" => 3, "security" => 5, "quantum_impact" => "X25519+Kyber hybrid; initial PQ protection.", "post_quantum_status" => 3, "example" => ["scenario" => "OTRv4 private deniable chat", "input" => ["identity_keys" => "ed448", "kem" => "kyber initial ke"], "output" => ["message" => "deniable encrypted"]], "flow" => ["dake handshake (dual ratchet + kyber)", "double ratchet messaging", "deniable signatures (ring sig)"], "related" => ["otr", "signal-double-ratchet", "mls"]],
        ["algo" => 668, "uuid" => "b370ab", "name" => "mtproto", "type" => "protocol", "status" => "active", "title" => "MTProto", "description_md" => "MTProto (Mobile Telegram Protocol) is Telegram's custom E2E encryption protocol. Used in Telegram Secret Chats (MTProto 2.0 with AES-256-IGE and SHA-256).\n\nMTProto 2.0 is Telegram's current protocol for secret chats. Regular Telegram cloud chats use MTProto but with server-access encryption (not E2E). Only Secret Chats are fully E2E.", "mental_model" => "Telegram custom E2E -- MTProto 2.0, Secret Chats only, custom crypto.", "purpose" => ["telegram secret chats e2e encryption"], "good_for" => ["telegram secret chats"], "avoid_for" => ["non-telegram (signal double ratchet better)", "regular telegram chats (not e2e)"], "pros" => ["telegram standard", "2.0 improved over 1.0"], "cons" => ["custom crypto (controversial)", "not e2e by default for groups/cloud", "not signal-standard"], "difficulty" => 3, "security" => 3, "quantum_impact" => "DH-based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Telegram Secret Chat E2E", "input" => ["auth_key" => "2048-bit dh key", "msg" => "plaintext"], "output" => ["ciphertext" => "mtproto2 aes-ige encrypted"]], "flow" => ["dh key agreement", "aes-256-ige with sha-256 auth key check"], "related" => ["signal-double-ratchet", "noise-xx", "otr"]],
        ["algo" => 669, "uuid" => "8e17ed", "name" => "wireguard", "type" => "protocol", "status" => "active", "title" => "WireGuard", "description_md" => "WireGuard is a modern, fast, secure VPN protocol using Noise IKpsk2 (X25519 + ChaCha20-Poly1305 + BLAKE2s). Designed for simplicity and high performance. Built into Linux kernel.\n\nWireGuard uses the exact Noise IKpsk2 handshake. Transport uses ChaCha20-Poly1305 AEAD. Much simpler codebase than OpenVPN or IPsec.", "mental_model" => "Modern VPN -- WireGuard, Noise IKpsk2, X25519, ChaCha20-Poly1305, Linux kernel.", "purpose" => ["modern high-performance vpn"], "good_for" => ["vpn tunneling", "linux kernel vpn", "iot vpn", "high performance secure tunnel"], "avoid_for" => ["complex site-to-site (ipsec feature-rich)", "enterprise legacy vpn"], "pros" => ["simple codebase", "high performance", "linux kernel standard", "noise framework", "forward secret"], "cons" => ["no TCP mode (UDP only)", "no built-in cert management"], "difficulty" => 1, "security" => 5, "quantum_impact" => "X25519 quantum-vulnerable; research on PQ WireGuard exists.", "post_quantum_status" => 1, "example" => ["scenario" => "WireGuard VPN tunnel", "input" => ["peer_pubkey" => "X25519 key", "psk" => "optional pre-shared key"], "output" => ["tunnel" => "ChaCha20-Poly1305 encrypted VPN"]], "flow" => ["Noise IKpsk2 handshake (X25519)", "ChaCha20-Poly1305 AEAD transport", "counter-based replay protection"], "related" => ["noise-ikpsk2", "noise-ik", "chacha20poly1305"]],
        ["algo" => 670, "uuid" => "5839f2", "name" => "mls", "type" => "protocol", "status" => "active", "title" => "MLS", "description_md" => "MLS (Messaging Layer Security) is the IETF RFC 9420 standard for end-to-end encrypted group messaging. Provides efficient group key updates with O(log N) message overhead.\n\nMLS uses a ratchet tree (binary tree of DH keys) for efficient group management. Used in Matrix, Cisco Webex, and Wickr.", "mental_model" => "IETF group E2EE -- MLS RFC 9420, O(log N) group key updates, ratchet tree.", "purpose" => ["ietf standard group e2ee messaging"], "good_for" => ["group e2ee messaging", "matrix mls", "cisco webex e2ee", "wickr enterprise"], "avoid_for" => ["1:1 messaging (signal double ratchet simpler)"], "pros" => ["ietf rfc 9420 standard", "o(log n) group updates", "forward secrecy", "post-compromise security", "webex/matrix standard"], "cons" => ["complex implementation", "group state management"], "difficulty" => 4, "security" => 5, "quantum_impact" => "DH ratchet tree; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "MLS group chat key rotation", "input" => ["group_state" => "ratchet tree", "update" => "member change"], "output" => ["new_epoch_key" => "group epoch key"]], "flow" => ["ratchet tree: binary DH tree over group", "member add/remove: tree update O(log n)", "epoch key: root of tree"], "related" => ["signal-double-ratchet", "pqxdh", "sesame"]],
        ["algo" => 671, "uuid" => "5f3ca0", "name" => "pqxdh", "type" => "protocol", "status" => "active", "title" => "PQXDH", "description_md" => "PQXDH (Post-Quantum Extended Diffie-Hellman) is Signal's upgrade to X3DH combining X25519 and CRYSTALS-Kyber for post-quantum secure initial key agreement.\n\nSignal deployed PQXDH in 2023 as a drop-in X3DH upgrade. Protects against harvest-now-decrypt-later attacks on initial key establishment.", "mental_model" => "Signal PQ upgrade -- PQXDH = X3DH + Kyber, 2023 Signal standard.", "purpose" => ["post-quantum initial key agreement (signal)"], "good_for" => ["signal pq protection", "x3dh pq upgrade", "harvest-now-decrypt-later resistance"], "avoid_for" => ["non-signal (use generic pq ke)"], "pros" => ["kyber pq protection", "signal 2023 standard", "drop-in x3dh upgrade", "harvest attack resistant"], "cons" => ["larger key bundles", "signal-ecosystem specific"], "difficulty" => 3, "security" => 5, "quantum_impact" => "X25519 + Kyber hybrid; strong PQ protection.", "post_quantum_status" => 4, "example" => ["scenario" => "Signal PQXDH initial message", "input" => ["IK" => "identity keys", "Kyber_prekey" => "kem prekey bundle"], "output" => ["sk" => "pq-protected shared key"]], "flow" => ["X3DH 4x DH as before", "additional Kyber KEM encapsulation", "KDF(x3dh_keys || kyber_ss) -> SK"], "related" => ["signal-x3dh", "ml-kem", "signal-double-ratchet"]],
        ["algo" => 672, "uuid" => "f20438", "name" => "cpace", "type" => "protocol", "status" => "active", "title" => "CPace", "description_md" => "CPace is a symmetric PAKE with a simple, provably secure design. Selected in IRTF CFRG recommendations alongside OPAQUE. Based on hash-to-curve.\n\nCPace (Composable Password Authenticated Connection Establishment) uses only one round trip. IRTF CFRG recommended alongside OPAQUE.", "mental_model" => "CFRG symmetric PAKE -- CPace, 1-RTT, hash-to-curve, IRTF standard.", "purpose" => ["cfrg symmetric pake"], "good_for" => ["simple symmetric pake", "irtf recommended", "1-rtt password auth"], "avoid_for" => ["augmented (opaque)", "offline attack concerns (opaque)"], "pros" => ["1 round trip", "simple", "irtf cfrg standard", "hash-to-curve based"], "cons" => ["symmetric (server has verifier)", "not augmented"], "difficulty" => 2, "security" => 4, "quantum_impact" => "DL-based.", "post_quantum_status" => 1, "example" => ["scenario" => "CPace symmetric password auth", "input" => ["password" => "shared password", "sid" => "session id"], "output" => ["sk" => "shared session key"]], "flow" => ["A: g = hash_to_curve(password,sid), X = x*g", "B: Y = y*g", "exchange X,Y -> KDF -> SK"], "related" => ["opaque", "spake2", "dragonfly", "aucpace"]],
        ["algo" => 673, "uuid" => "0ebbaa", "name" => "aucpace", "type" => "protocol", "status" => "active", "title" => "AuCPace", "description_md" => "AuCPace is an augmented version of CPace (CFRG-recommended PAKE family). The server stores a password verifier rather than the password, providing augmented security similar to SPAKE2+.\n\nAuCPace combines CPace's simplicity with augmented protection -- server verifier prevents direct password recovery from server compromise.", "mental_model" => "Augmented CPace -- CFRG PAKE, server verifier, CPace family.", "purpose" => ["augmented cpace pake"], "good_for" => ["augmented cpace security", "cfrg pake augmented"], "avoid_for" => ["full asymmetric (opaque)", "simple symmetric (cpace)"], "pros" => ["augmented server verifier", "cpace family", "cfrg aligned"], "cons" => ["less deployed than spake2+/opaque"], "difficulty" => 2, "security" => 4, "quantum_impact" => "DL-based.", "post_quantum_status" => 1, "example" => ["scenario" => "AuCPace augmented login", "input" => ["password" => "user pw", "verifier" => "server augmented record"], "output" => ["session_key" => "shared key"]], "flow" => ["cpace augmented exchange with server verifier"], "related" => ["cpace", "spake2+", "opaque"]],
        ["algo" => 675, "uuid" => "0784f1", "name" => "kemtls", "type" => "protocol", "status" => "active", "title" => "KEMTLS", "description_md" => "KEMTLS replaces the TLS 1.3 signature-based server authentication with KEM-based authentication, reducing handshake latency while achieving post-quantum security.\n\nKEMTLS uses ML-KEM instead of signature-based certificates for server auth, enabling PQ-safe TLS without digital signatures in the critical path.", "mental_model" => "PQ TLS without signatures -- KEMTLS, KEM-based server auth, post-quantum TLS.", "purpose" => ["post-quantum tls via kem auth"], "good_for" => ["pq tls handshake", "kem-based server auth", "post-quantum web security"], "avoid_for" => ["standard tls (kemtls needs kem cert infra)"], "pros" => ["post-quantum tls", "kem based (no sig overhead)", "lower latency potential"], "cons" => ["requires kem certificate infrastructure", "deployment complexity"], "difficulty" => 4, "security" => 5, "quantum_impact" => "KEM-based; strong post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "KEMTLS post-quantum server auth", "input" => ["server_kem_cert" => "ML-KEM public key cert"], "output" => ["session" => "pq-authenticated tls session"]], "flow" => ["client encapsulates to server KEM pubkey", "server decapsulates: mutual auth + key", "no digital signatures needed"], "related" => ["ml-kem", "pq-tls-hybrid", "signal-double-ratchet"]],
        ["algo" => 676, "uuid" => "de8b94", "name" => "pq-tls-hybrid", "type" => "protocol", "status" => "active", "title" => "PQ TLS Hybrid", "description_md" => "PQ TLS Hybrid combines classical key exchange (X25519/P-256) with post-quantum KEM (ML-KEM/Kyber) in TLS 1.3 handshakes. If either component is secure, the session is secure.\n\nChrome, Cloudflare, and NIST recommend PQ hybrid TLS as the transition path. X25519Kyber768 is the common combination (IETF draft).", "mental_model" => "Hybrid PQ TLS -- X25519+Kyber in TLS 1.3, Chrome/Cloudflare standard, safe migration.", "purpose" => ["hybrid pq+classical tls 1.3"], "good_for" => ["tls pq migration", "chrome cloudflare pq tls", "harvest attack protection"], "avoid_for" => ["full pq only (kemtls)", "classical only (tls 1.3)"], "pros" => ["safe migration (both must break)", "chrome standard", "cloudflare deployed", "x25519kyber768 ietf draft"], "cons" => ["larger key exchange (kem sizes)", "transitional"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Hybrid PQ; strong if either component holds.", "post_quantum_status" => 4, "example" => ["scenario" => "Chrome TLS hybrid PQ connection", "input" => ["x25519_key" => "classical ke", "kyber_key" => "pq kem"], "output" => ["session" => "hybrid tls 1.3 session"]], "flow" => ["TLS 1.3 client hello with X25519Kyber768 group", "combined KDF over x25519 + kyber outputs"], "related" => ["kemtls", "ml-kem", "noise-ikpsk2"]],
        ["algo" => 677, "uuid" => "d4decf", "name" => "ech", "type" => "protocol", "status" => "active", "title" => "ECH", "description_md" => "ECH (Encrypted Client Hello) is a TLS 1.3 extension that encrypts the ClientHello (including SNI) to prevent network observers from seeing which server the client is connecting to.\n\nECH solves the SNI privacy leak in TLS. The client encrypts its ClientHello using the server's public key from DNS (HTTPS record). Supported in Chrome, Firefox, Cloudflare.", "mental_model" => "Encrypted SNI (TLS ClientHello) -- ECH, hides target server from network observers.", "purpose" => ["encrypted tls client hello / sni privacy"], "good_for" => ["sni privacy", "tls client hello encryption", "cloudflare chrome privacy"], "avoid_for" => ["non-tls", "private networks where sni leak ok"], "pros" => ["sni privacy", "chrome firefox standard", "cloudflare deployed", "tls 1.3 extension"], "cons" => ["dns https record required", "server must publish ech config"], "difficulty" => 2, "security" => 4, "quantum_impact" => "HPKE-based; hybrid PQ possible.", "post_quantum_status" => 2, "example" => ["scenario" => "ECH encrypted SNI connection", "input" => ["ech_config" => "from dns https record", "sni" => "target server"], "output" => ["tls_session" => "sni hidden from network"]], "flow" => ["fetch ECH config from DNS HTTPS record", "encrypt ClientHello inner with HPKE", "send outer ClientHello with encrypted_client_hello ext"], "related" => ["pq-tls-hybrid", "privacy-pass", "oblivious-http"]],
        ["algo" => 678, "uuid" => "6d545a", "name" => "odohdtls", "type" => "protocol", "status" => "active", "title" => "ODoH-DTLS", "description_md" => "ODoH (Oblivious DNS over HTTPS) over DTLS adds oblivious relay to DNS privacy. Combines Oblivious HTTP with DTLS transport to hide DNS query origin from resolver.\n\nThe client sends DNS queries through an oblivious relay so neither the relay nor the resolver sees both the client identity and the query content.", "mental_model" => "Oblivious DNS over DTLS -- hides client identity from DNS resolver via relay.", "purpose" => ["oblivious dns privacy via relay"], "good_for" => ["dns query privacy", "resolver cannot link client + query"], "avoid_for" => ["non-dns privacy (oblivious-http more general)"], "pros" => ["dns privacy", "resolver unlinks identity from query", "dtls efficient"], "cons" => ["relay trust required", "latency overhead"], "difficulty" => 3, "security" => 4, "quantum_impact" => "HPKE-based.", "post_quantum_status" => 2, "example" => ["scenario" => "ODoH DNS privacy query", "input" => ["dns_query" => "example.com", "relay" => "trusted relay"], "output" => ["response" => "dns answer (unlinkable)"]], "flow" => ["encrypt query with HPKE to resolver key", "send via relay", "resolver decrypts, responds", "relay forwards"], "related" => ["oblivious-http", "privacy-pass", "ech"]],
        ["algo" => 679, "uuid" => "dfd9c3", "name" => "oblivious-http", "type" => "protocol", "status" => "active", "title" => "Oblivious HTTP", "description_md" => "Oblivious HTTP (OHTTP, RFC 9458) uses a relay + HPKE to separate client identity from request content. The relay sees the client but not the message; the gateway sees the message but not the client.\n\nOHTTP enables privacy-preserving HTTP requests. Used in Apple Private Relay DNS, Firefox private browsing telemetry, and privacy-pass token issuance.", "mental_model" => "HTTP with identity-content separation -- OHTTP RFC 9458, relay+HPKE, Apple Private Relay.", "purpose" => ["client-unlinkable http requests"], "good_for" => ["apple private relay dns", "privacy telemetry", "oblivious http api calls"], "avoid_for" => ["authenticated sessions (breaks identity separation)"], "pros" => ["rfc 9458 standard", "apple deployed", "relay/gateway separation", "hpke standard"], "cons" => ["relay trust required", "stateless (no session continuity)"], "difficulty" => 2, "security" => 4, "quantum_impact" => "HPKE-based.", "post_quantum_status" => 2, "example" => ["scenario" => "OHTTP privacy-preserving API call", "input" => ["request" => "http request", "gateway_key" => "hpke pubkey"], "output" => ["response" => "unlinkable"]], "flow" => ["client: HPKE encapsulate to gateway key", "send via relay (relay knows client, not content)", "gateway: HPKE decapsulate, process, respond"], "related" => ["privacy-pass", "odohdtls", "ech"]],
        ["algo" => 680, "uuid" => "df5c91", "name" => "privacy-pass", "type" => "protocol", "status" => "active", "title" => "Privacy Pass", "description_md" => "Privacy Pass (RFC 9576/9577) is an anonymous token protocol using blind signatures or OPRFs to issue rate-limiting tokens without linking issuance to redemption.\n\nPrivacy Pass solves CAPTCHAs anonymously. CloudFlare, Apple, and Fastly use Privacy Pass to let trusted clients bypass CAPTCHAs without revealing identity. Tokens are unlinkable.", "mental_model" => "Anonymous rate-limit tokens -- Privacy Pass, unlinkable CAPTCHA bypass, Cloudflare/Apple.", "purpose" => ["anonymous rate-limit / captcha bypass tokens"], "good_for" => ["captcha bypass", "cloudflare privacy pass", "apple private access tokens", "unlinkable auth tokens"], "avoid_for" => ["authenticated sessions (not anonymous)"], "pros" => ["unlinkable tokens", "rfc 9576 standard", "cloudflare/apple deployed", "blind signature based"], "cons" => ["token management", "double-spend protection needed"], "difficulty" => 3, "security" => 4, "quantum_impact" => "RSA/DL blind sig; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Privacy Pass CAPTCHA bypass", "input" => ["challenge" => "captcha token request"], "output" => ["token" => "unlinkable anonymous token"]], "flow" => ["issuance: blind the token, server signs", "unblind: get signed token", "redemption: present token (unlinkable to issuance)"], "related" => ["oblivious-http", "odohdtls", "ech"]],
        ["algo" => 681, "uuid" => "9b9a39", "name" => "masque", "type" => "protocol", "status" => "active", "title" => "MASQUE", "description_md" => "MASQUE (Multiplexed Application Substrate over QUIC Encryption) is an IETF protocol for HTTP/3-based tunneling. Enables proxying UDP, TCP, and IP over HTTPS/QUIC connections.\n\nMASQUE powers Apple iCloud Private Relay and Cloudflare 1.1.1.1 VPN. It provides VPN-like tunneling embedded within standard HTTPS/QUIC traffic.", "mental_model" => "HTTP/3 QUIC tunneling VPN -- MASQUE, Apple iCloud Private Relay, standard-looking traffic.", "purpose" => ["quic-based http/3 proxy tunneling"], "good_for" => ["apple icloud private relay", "quic vpn tunneling", "censorship-resistant tunneling"], "avoid_for" => ["wireguard (simpler vpn)"], "pros" => ["http/3 embedded (hard to block)", "apple deployed", "ietf standard", "quic multiplexed"], "cons" => ["quic dependency", "complex vs wireguard"], "difficulty" => 3, "security" => 4, "quantum_impact" => "TLS 1.3 / QUIC based.", "post_quantum_status" => 2, "example" => ["scenario" => "iCloud Private Relay MASQUE proxy", "input" => ["target" => "destination server", "quic" => "h3 connection"], "output" => ["tunnel" => "proxied quic stream"]], "flow" => ["CONNECT-UDP/CONNECT-IP over HTTP/3", "relay chain obscures client identity"], "related" => ["oblivious-http", "wireguard", "privacy-pass"]],
        ["algo" => 682, "uuid" => "8fa268", "name" => "edhoc", "type" => "protocol", "status" => "active", "title" => "EDHOC", "description_md" => "EDHOC (Ephemeral Diffie-Hellman Over COSE) is an IETF (RFC 9528) lightweight key exchange protocol for constrained IoT devices. Provides mutual authentication and session key establishment in very few bytes.\n\nEDHOC uses COSE (CBOR Object Signing and Encryption) and EDHOC messages fit in small CoAP payloads, suitable for LoRa/6LoWPAN IoT devices.", "mental_model" => "Lightweight IoT key exchange -- EDHOC RFC 9528, CBOR/COSE, CoAP-compatible.", "purpose" => ["lightweight iot key exchange"], "good_for" => ["iot constrained devices", "coap iot protocols", "lorawan iot ke"], "avoid_for" => ["full tls environments (use tls 1.3)"], "pros" => ["tiny messages", "rfc 9528 standard", "cose/cbor efficient", "coap compatible"], "cons" => ["iot-specific", "limited crypto agility"], "difficulty" => 2, "security" => 4, "quantum_impact" => "DH-based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "EDHOC IoT sensor key exchange", "input" => ["G_X" => "initiator ephemeral", "credentials" => "iot cert"], "output" => ["oscore_context" => "edhoc session -> oscore"]], "flow" => ["message 1: G_X, METHOD_CORR", "message 2: G_Y, ciphertext_2 (signed+enc)", "message 3: ciphertext_3", "derive OSCORE master secret"], "related" => ["oscore", "dtls12", "dtls13"]],
        ["algo" => 683, "uuid" => "550681", "name" => "oscore", "type" => "protocol", "status" => "active", "title" => "OSCORE", "description_md" => "OSCORE (Object Security for Constrained RESTful Environments, RFC 8613) provides end-to-end E2E security for CoAP messages at the object level. Works across proxies.\n\nOSCORE encrypts CoAP at the application layer so proxies in the path cannot read payloads. Used with EDHOC for IoT key establishment.", "mental_model" => "CoAP E2E object security -- OSCORE RFC 8613, application-layer e2e for IoT proxies.", "purpose" => ["end-to-end coap security (iot)"], "good_for" => ["coap e2e security through proxies", "iot application layer e2e"], "avoid_for" => ["non-coap (use tls/dtls)"], "pros" => ["e2e through proxies", "rfc 8613 standard", "coap native", "edhoc integration"], "cons" => ["coap-specific", "requires oscore context management"], "difficulty" => 2, "security" => 4, "quantum_impact" => "AES-CCM/GCM based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "OSCORE IoT CoAP E2E", "input" => ["coap_request" => "GET /sensor", "oscore_context" => "edhoc-derived"], "output" => ["protected_coap" => "oscore-encrypted request"]], "flow" => ["encode coap options into AAD", "AEAD encrypt (AES-CCM/GCM)", "transport via CoAP (proxy-transparent)"], "related" => ["edhoc", "dtls12", "dtls13"]],
        ["algo" => 684, "uuid" => "450c08", "name" => "dtls12", "type" => "protocol", "status" => "active", "title" => "DTLS 1.2", "description_md" => "DTLS 1.2 (Datagram TLS, RFC 6347) is TLS for UDP datagrams. Provides the same security guarantees as TLS 1.2 for datagram-based protocols like VoIP, gaming, and IoT.\n\nDTLS 1.2 is the standard for securing UDP communications. Used in WebRTC (data channels), SRTP key exchange, and CoAP security.", "mental_model" => "TLS for UDP -- DTLS 1.2, WebRTC data channels, VoIP security, CoAP.", "purpose" => ["tls-equivalent security for udp/datagrams"], "good_for" => ["webrtc data channels", "voip security", "iot coap", "udp-based protocols"], "avoid_for" => ["tcp streams (tls 1.3)", "dtls 1.3 preferred for new code"], "pros" => ["tls for udp", "rfc 6347 standard", "webrtc standard", "replay protection"], "cons" => ["deprecated by dtls 1.3", "tls 1.2 era weaknesses"], "difficulty" => 2, "security" => 3, "quantum_impact" => "DH/RSA classical; pre-PQ.", "post_quantum_status" => 1, "example" => ["scenario" => "WebRTC DTLS data channel", "input" => ["udp_socket" => "browser-browser", "cert" => "self-signed"], "output" => ["dtls_session" => "secure datagram channel"]], "flow" => ["dtls handshake over udp (retransmit if lost)", "record protocol: encrypt datagrams with epoch/seq"], "related" => ["dtls13", "oscore", "edhoc"]],
        ["algo" => 685, "uuid" => "70a9ca", "name" => "dtls13", "type" => "protocol", "status" => "active", "title" => "DTLS 1.3", "description_md" => "DTLS 1.3 (RFC 9147) is DTLS updated to match TLS 1.3 security properties. Removes legacy cipher suites, improves 0-RTT, and aligns with TLS 1.3 handshake.\n\nDTLS 1.3 is the current standard for UDP security. WebRTC is migrating to DTLS 1.3 for improved security and performance.", "mental_model" => "TLS 1.3 for UDP -- DTLS 1.3 RFC 9147, modern datagram security.", "purpose" => ["tls 1.3 equivalent security for udp"], "good_for" => ["modern webrtc", "iot dtls", "udp 0-rtt"], "avoid_for" => ["legacy (dtls 1.2 required)", "tcp streams (tls 1.3)"], "pros" => ["tls 1.3 security", "rfc 9147", "0-rtt support", "pfs mandatory"], "cons" => ["new, less deployed", "dtls complexity"], "difficulty" => 2, "security" => 5, "quantum_impact" => "DH based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "DTLS 1.3 IoT secure channel", "input" => ["udp_socket" => "sensor", "cert" => "device cert"], "output" => ["dtls13_session" => "forward-secret datagram channel"]], "flow" => ["dtls 1.3 handshake (tls 1.3 adapted)", "epoch-based key updates"], "related" => ["dtls12", "oscore", "edhoc"]],
        ["algo" => 686, "uuid" => "7cdf9d", "name" => "noise-xxfallback", "type" => "protocol", "status" => "active", "title" => "Noise XXfallback", "description_md" => "Noise XXfallback is a Noise pattern for handling fallback when the initial handshake fails (e.g., responder does not recognize initiator's key). Used in WireGuard for re-handshake fallback scenarios.", "mental_model" => "Noise fallback handshake -- XXfallback, WireGuard re-handshake, handles unknown initiator.", "purpose" => ["noise fallback handshake for unknown initiator"], "good_for" => ["wireguard fallback", "unknown initiator handling"], "avoid_for" => ["standard handshakes (noise-ik/xx)"], "pros" => ["wireguard fallback standard", "handles unknown initiator"], "cons" => ["special case only"], "difficulty" => 2, "security" => 5, "quantum_impact" => "DH-based.", "post_quantum_status" => 1, "example" => ["scenario" => "WireGuard fallback handshake", "input" => ["unknown_initiator" => "unrecognized key"], "output" => ["session" => "fallback xx session"]], "flow" => ["initial ik fails (unknown initiator)", "fallback to noise xx exchange"], "related" => ["noise-xx", "noise-ik", "wireguard"]],
        ["algo" => 687, "uuid" => "e6e02d", "name" => "disco", "type" => "protocol", "status" => "active", "title" => "Disco", "description_md" => "Disco integrates the Strobe protocol framework with the Noise Protocol Framework, replacing HKDF and other symmetric primitives with a single Strobe instance.\n\nDisco simplifies the symmetric crypto in Noise by using Strobe (based on Keccak/SHAKE) for all hash, PRF, and AEAD operations.", "mental_model" => "Noise+Strobe integration -- Disco, unified Keccak/SHAKE for all Noise symmetric ops.", "purpose" => ["simplified noise with strobe/keccak"], "good_for" => ["simplified noise implementation", "strobe-based protocols", "keccak unified crypto"], "avoid_for" => ["standard noise (well-tested)", "non-strobe environments"], "pros" => ["simplified implementation", "single keccak primitive", "noise + strobe unified"], "cons" => ["less deployed", "strobe less widely audited than noise+sha"], "difficulty" => 3, "security" => 4, "quantum_impact" => "DH-based (hash PQ-compatible).", "post_quantum_status" => 1, "example" => ["scenario" => "Disco simplified Noise handshake", "input" => ["strobe_state" => "keccak based", "noise_pattern" => "XX"], "output" => ["session" => "disco secure channel"]], "flow" => ["noise handshake using strobe for all crypto", "send/recv via strobe encrypt/decrypt"], "related" => ["noise-xx", "noise-ik", "noisesocket"]],
        ["algo" => 688, "uuid" => "bd911d", "name" => "noisesocket", "type" => "protocol", "status" => "active", "title" => "NoiseSocket", "description_md" => "NoiseSocket adds framing, negotiation, and versioning on top of the Noise Protocol Framework to create a drop-in TLS alternative with Noise security.\n\nNoiseSocket provides length-prefixed framing and pattern negotiation so Noise can be used like TLS as a general secure channel.", "mental_model" => "Noise with TLS-like framing -- NoiseSocket, drop-in TLS replacement, pattern negotiation.", "purpose" => ["tls-like framing for noise protocol"], "good_for" => ["noise as tls drop-in", "custom secure channel with noise"], "avoid_for" => ["standard tls (interoperability)"], "pros" => ["tls-like usability", "noise security", "pattern negotiation", "framing included"], "cons" => ["less deployed than tls", "niche"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Noise DH-based.", "post_quantum_status" => 1, "example" => ["scenario" => "NoiseSocket drop-in TLS replacement", "input" => ["noise_pattern" => "XX", "socket" => "tcp conn"], "output" => ["secure_channel" => "noisesocket session"]], "flow" => ["noise negotiation frame", "noise handshake (selected pattern)", "framed transport"], "related" => ["noise-xx", "disco", "noise-ik"]],
        ["algo" => 691, "uuid" => "ec0e3d", "name" => "zrtp", "type" => "protocol", "status" => "active", "title" => "ZRTP", "description_md" => "ZRTP (Z Real-time Transport Protocol, RFC 6189) is a key agreement protocol for securing VoIP/media streams. Provides E2E key exchange for SRTP without PKI, using a Short Authentication String (SAS) for MitM prevention.\n\nZRTP enables E2E encrypted phone calls without certificates. Users verbally compare a short authentication string to detect MITM.", "mental_model" => "E2E VoIP key exchange -- ZRTP, SAS verbal verification, Linphone/Signal Phone standard.", "purpose" => ["voip e2e key exchange without pki"], "good_for" => ["e2e voip encryption", "linphone zrtp", "signal phone calls (srtp+zrtp)", "srtp key exchange"], "avoid_for" => ["non-voip (signal double ratchet better)"], "pros" => ["no pki required", "sas mitm detection", "rfc 6189 standard", "linphone deployed"], "cons" => ["sas comparison required", "voip-specific"], "difficulty" => 2, "security" => 4, "quantum_impact" => "DH-based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "ZRTP VoIP E2E call", "input" => ["voip_stream" => "rtp", "dh" => "zrtp dh exchange"], "output" => ["srtp_keys" => "e2e encrypted call", "sas" => "verbal verify"]], "flow" => ["zrtp hello exchanged in-band", "dh agreement over rtp", "srtp session keys derived", "sas displayed for verbal verification"], "related" => ["dtls12", "signal-double-ratchet", "noise-xx"]],
        ["algo" => 693, "uuid" => "a31000", "name" => "hmqv", "type" => "protocol", "status" => "active", "title" => "HMQV", "description_md" => "HMQV (Hashed MQV) is a hashed variant of MQV (Menezes-Qu-Vanstone) key agreement that achieves full eCK-model security. Efficient mutual authentication with implicit authentication.\n\nHMQV provides authenticated key exchange more efficiently than STS/IKE with strong eCK security proofs. Used in some TLS and IKE implementations.", "mental_model" => "Hashed MQV -- efficient mutually-authenticated KE, eCK security, IKE/TLS variant.", "purpose" => ["efficient mutually authenticated key exchange"], "good_for" => ["eck-secure authenticated ke", "ike/tls auth ke", "mqv family protocols"], "avoid_for" => ["simple dh (no auth)", "signal/noise (better for messaging)"], "pros" => ["eck-model security", "efficient", "implicit mutual auth"], "cons" => ["patent history (mqv)", "less common than noise/tls", "classical only"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DL-based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "HMQV mutual auth key agreement", "input" => ["static_a" => "A long-term key", "eph_a" => "A ephemeral", "static_b" => "B key"], "output" => ["shared_key" => "hmqv session key"]], "flow" => ["HMQV: combine ephemeral + static DH with hash", "both parties compute same key", "implicit authentication"], "related" => ["yak", "sts", "noise-kk", "speke"]],
        ["algo" => 694, "uuid" => "85eae7", "name" => "yak", "type" => "protocol", "status" => "active", "title" => "YAK", "description_md" => "YAK (Yet Another Key agreement) is an authenticated key exchange protocol based on Schnorr signatures combined with DH. Achieves eCK security with forward secrecy and explicit mutual authentication.\n\nYAK provides a simple, patent-free alternative to HMQV and STS with explicit mutual authentication via Schnorr proofs.", "mental_model" => "Schnorr-DH mutual auth KE -- YAK, eCK security, patent-free MQV alternative.", "purpose" => ["schnorr-based mutually authenticated key exchange"], "good_for" => ["patent-free mutual auth ke", "schnorr-dh protocols"], "avoid_for" => ["simple dh", "noise-based protocols"], "pros" => ["patent-free", "eck security", "explicit mutual auth", "schnorr based"], "cons" => ["less deployed", "classical only"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DL-based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "YAK mutual auth session", "input" => ["static_a" => "long-term key A", "eph_a" => "ephemeral A"], "output" => ["session_key" => "yak authenticated key"]], "flow" => ["exchange ephemeral keys + schnorr proofs", "both verify proofs + derive shared key"], "related" => ["hmqv", "sts", "noise-kk"]],
        ["algo" => 695, "uuid" => "a07e0d", "name" => "sesame", "type" => "protocol", "status" => "active", "title" => "Sesame", "description_md" => "Sesame is a session management algorithm for the Signal Protocol that handles multiple devices per user and out-of-order message delivery in group contexts.\n\nSesame coordinates which ratchet session to use when a user has multiple devices (e.g., Signal Desktop + Signal Phone), maintaining separate Double Ratchet sessions per device pair.", "mental_model" => "Signal multi-device session manager -- Sesame, coordinates Double Ratchet per device.", "purpose" => ["multi-device signal session management"], "good_for" => ["signal multi-device e2ee", "multi-device ratchet coordination"], "avoid_for" => ["single device (double ratchet sufficient)"], "pros" => ["multi-device signal support", "per-device ratchet sessions", "out-of-order delivery"], "cons" => ["complex state management", "signal-ecosystem"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DH-based (double ratchet).", "post_quantum_status" => 1, "example" => ["scenario" => "Signal multi-device message delivery", "input" => ["devices" => ["phone", "desktop"], "msg" => "plaintext"], "output" => ["encrypted_msgs" => "per-device ratchet encrypted"]], "flow" => ["maintain separate double ratchet per (sender,recipient,device)", "route to correct ratchet session", "out-of-order buffer handling"], "related" => ["signal-double-ratchet", "mls", "signal-x3dh"]],
    ],
    "legacy" => [
        ["algo" => 663, "uuid" => "5ce4a0", "name" => "srp", "type" => "protocol", "status" => "legacy", "title" => "SRP", "description_md" => "SRP (Secure Remote Password, RFC 2945) is a symmetric PAKE that allows password-based authentication without sending the password over the network. Uses a verifier stored on the server.\n\nSRP was widely used in Apple iCloud, Kerberos, and ProtonMail historically. OPAQUE and CPace are now preferred.", "mental_model" => "Legacy symmetric PAKE -- SRP RFC 2945, password auth without transmission, superseded by OPAQUE.", "purpose" => ["legacy symmetric pake authentication"], "good_for" => ["legacy srp deployments", "historical protonmail/apple auth"], "avoid_for" => ["new projects (opaque/cpace/spake2+)"], "pros" => ["rfc standard", "deployed history"], "cons" => ["weaker than opaque", "computationally heavier", "legacy"], "difficulty" => 2, "security" => 3, "quantum_impact" => "DL-based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "SRP legacy login", "input" => ["password" => "user pw", "verifier" => "server stored"], "output" => ["session_key" => "srp session"]], "flow" => ["client: X = H(salt,pw)", "server: verifier V = g^x", "exchange and verify"], "related" => ["opaque", "spake2", "cpace"]],
        ["algo" => 664, "uuid" => "e5638b", "name" => "j-pake", "type" => "protocol", "status" => "legacy", "title" => "J-PAKE", "description_md" => "J-PAKE (Password Authenticated Key Exchange by Juggling) is a symmetric PAKE using two rounds of Schnorr ZKPs. Used in Firefox Sync and Thread IoT.\n\nJ-PAKE is RFC 8236. Still used in Thread/OpenThread IoT commissioning but superseded by CPace/OPAQUE for new deployments.", "mental_model" => "Legacy Schnorr PAKE -- J-PAKE, Firefox Sync/Thread IoT, ZKP-juggling.", "purpose" => ["legacy schnorr-zkp pake"], "good_for" => ["thread iot commissioning", "legacy firefox sync", "rfc 8236 deployments"], "avoid_for" => ["new deployments (cpace/opaque)"], "pros" => ["rfc 8236 standard", "thread iot standard", "two-round zk"], "cons" => ["2 rounds (cpace 1 round)", "heavier than cpace"], "difficulty" => 2, "security" => 3, "quantum_impact" => "DL-based.", "post_quantum_status" => 1, "example" => ["scenario" => "Thread IoT device commissioning", "input" => ["password" => "device pw", "zkps" => "schnorr proofs"], "output" => ["session_key" => "j-pake key"]], "flow" => ["round 1: commitments + zkp", "round 2: key material + zkp", "session key derived"], "related" => ["cpace", "spake2", "opaque", "srp"]],
        ["algo" => 666, "uuid" => "7006d5", "name" => "otr", "type" => "protocol", "status" => "legacy", "title" => "OTR", "description_md" => "OTR (Off-the-Record Messaging) is the original deniable E2E messaging protocol using AES-CTR + HMAC-SHA1 + DH ratchet. Precursor to Signal Double Ratchet.\n\nOTR was widely used in XMPP/Jabber clients (Pidgin, Adium). Superseded by OTRv4 and Signal Double Ratchet for new deployments.", "mental_model" => "Original deniable e2ee messaging -- OTR, XMPP/Pidgin standard, Signal precursor.", "purpose" => ["legacy deniable e2e messaging"], "good_for" => ["legacy xmpp otr", "historical reference"], "avoid_for" => ["new messaging (signal double ratchet/otrv4)"], "pros" => ["deniability", "forward secrecy", "pioneered e2e messaging"], "cons" => ["no multi-device", "sha1 hmac", "superseded"], "difficulty" => 2, "security" => 2, "quantum_impact" => "DH-based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Pidgin OTR chat", "input" => ["msg" => "plaintext", "dh_ratchet" => "otr ratchet"], "output" => ["encrypted" => "otr aes-ctr message"]], "flow" => ["dh ratchet + aes-ctr encrypt + hmac-sha1"], "related" => ["otrv4", "signal-double-ratchet", "noise-xx"]],
        ["algo" => 674, "uuid" => "8a9578", "name" => "speke", "type" => "protocol", "status" => "legacy", "title" => "SPEKE", "description_md" => "SPEKE (Simple Password Exponential Key Exchange) is an early PAKE using a password-derived generator. Historically used in Bluetooth pairing and some SSL VPNs.\n\nSPEKE is patented and now considered legacy. CPace is its open patent-free successor in the CFRG.", "mental_model" => "Legacy password-derived-generator PAKE -- SPEKE, Bluetooth history, CPace predecessor.", "purpose" => ["legacy pake (bluetooth historical)"], "good_for" => ["legacy bluetooth/vpn reference"], "avoid_for" => ["new deployments (cpace replaces)"], "pros" => ["simple design"], "cons" => ["patented", "legacy", "cpace supersedes"], "difficulty" => 2, "security" => 3, "quantum_impact" => "DL-based.", "post_quantum_status" => 1, "example" => ["scenario" => "SPEKE legacy pairing", "input" => ["password" => "shared pw"], "output" => ["session_key" => "speke key"]], "flow" => ["g = H(password) as group generator", "standard DH exchange with g"], "related" => ["cpace", "spake2", "dragonfly"]],
        ["algo" => 689, "uuid" => "40a269", "name" => "curvecp", "type" => "protocol", "status" => "legacy", "title" => "CurveCP", "description_md" => "CurveCP is a secure communication protocol by DJB (Daniel J. Bernstein) using Curve25519/NaCl. Designed as a secure TCP replacement -- forward secrecy and authentication with minimal complexity.\n\nCurveCP is superseded by Noise Protocol and WireGuard which are more widely deployed. MinimalT is a related protocol.", "mental_model" => "DJB secure TCP replacement -- CurveCP, Curve25519/NaCl, superseded by Noise/WireGuard.", "purpose" => ["legacy secure tcp alternative (djb)"], "good_for" => ["historical djb reference", "nacl-based protocol study"], "avoid_for" => ["new deployments (noise/wireguard)"], "pros" => ["forward secrecy", "djb/nacl standard", "simple"], "cons" => ["superseded by noise/wireguard", "limited adoption"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Curve25519; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "CurveCP secure connection", "input" => ["server_key" => "curve25519", "client_key" => "curve25519"], "output" => ["secure_channel" => "nacl box encrypted"]], "flow" => ["curve25519 dh", "nacl secretbox for transport"], "related" => ["noise-xx", "wireguard", "minimalt"]],
        ["algo" => 690, "uuid" => "bbf6d7", "name" => "minimalt", "type" => "protocol", "status" => "legacy", "title" => "MinimalT", "description_md" => "MinimalT is a minimal secure transport protocol based on CurveCP with UDP transport. Designed for low latency, forward secrecy, and simplicity using NaCl primitives.", "mental_model" => "Minimal NaCl UDP transport -- MinimalT, CurveCP UDP variant, superseded by WireGuard/QUIC.", "purpose" => ["legacy minimal nacl udp transport"], "good_for" => ["legacy reference", "nacl transport study"], "avoid_for" => ["new deployments (wireguard/quic)"], "pros" => ["minimal simple", "nacl primitives", "forward secrecy udp"], "cons" => ["superseded", "niche"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Curve25519; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "MinimalT UDP secure channel", "input" => ["keys" => "nacl keys"], "output" => ["session" => "minimalt channel"]], "flow" => ["nacl-based udp transport", "forward-secret sessions"], "related" => ["curvecp", "wireguard", "noise-xx"]],
        ["algo" => 692, "uuid" => "5c113a", "name" => "sts", "type" => "protocol", "status" => "legacy", "title" => "STS", "description_md" => "STS (Station-to-Station) is a classic authenticated Diffie-Hellman key agreement protocol using digital signatures for mutual authentication. The conceptual basis for IKE and many TLS variants.\n\nSTS is the theoretical ancestor of TLS handshakes and IKEv2. Provides mutual authentication via signature exchange alongside DH.", "mental_model" => "Classic signature-DH mutual auth -- STS, IKE ancestor, TLS handshake basis.", "purpose" => ["classic mutually authenticated dh key exchange"], "good_for" => ["protocol theory", "ike/tls conceptual basis"], "avoid_for" => ["production (use tls 1.3/noise-xx)"], "pros" => ["conceptually simple", "ike/tls foundation"], "cons" => ["legacy theoretical only", "no forward secrecy alone"], "difficulty" => 2, "security" => 3, "quantum_impact" => "DH+signatures; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "STS mutual auth DH", "input" => ["g_x" => "initiator dh", "g_y" => "responder dh", "sig_a" => "initiator signature"], "output" => ["session_key" => "sts shared key"]], "flow" => ["exchange DH values g^x, g^y", "sign DH values for authentication", "verify sigs, compute g^xy"], "related" => ["hmqv", "yak", "noise-kk"]],
    ]
